VALUES
  ('fire-eq-eng-moex-01113', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「消防幫浦加壓送水裝置等及配管摩擦損失計算基準」中有關幫浦規定之敘述，何者錯誤？', '["幫浦之出水量在額定出水量之150% 時，其全揚程應達到額定出水量；性能曲線上全揚程之55% 以上", "全閉揚程應為性能曲線上全揚程之140% 以下", "幫浦所標示之出水量，在其性能曲線上之全揚程必須達到所標示揚程之100%至110% 之間", "在額定出水量150% 時，其軸動力不得超過馬達額定輸出馬力之110%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01114', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關瓦斯漏氣檢知器設置場所之敘述，何者錯誤？', '["得設在出入口附近外氣流通之場所", "不得設在明顯無法確保檢知器性能之場所", "不得設在瓦斯燃燒器具之廢氣容易接觸之場所", "不得設在距出風口1.5公尺內之場所"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01115', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關消防防護計畫內容之敘述何者錯誤？', '["自衛消防編組員工在50人以上者，應增編安全防護班及救護班", "滅火、通報及避難訓練之實施；每半年至少應舉辦一次", "滅火、通報及避難訓練之實施，每次不得少於8小時，並應事先通報當地消防機關", "防火避難設施之自行檢查：每月至少檢查一次"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01116', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法規定，下列有關擋牆之規定，何者錯誤？', '["厚度在15公分以上之鋼筋或鋼骨混凝土牆", "設置位置距離場所外牆或相當於該外牆之設施外側1公尺以上", "厚度在20公分以上之鋼筋或鋼骨補強空心磚牆", "堆高斜度不超過60度之土堤"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01117', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '無故撥火警電話者，可處罰鍰新台幣：', '["1千元以上，6千元以下", "3千元以上，1萬5千元以下", "6千元以上，3萬元以下", "1萬元以上，5萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01118', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，關於出口標示燈於易識別該燈情形時，出口標示燈之有效範圍， 指至該燈之步行距離，下列敘述何者正確？', '["A級：未顯示避難方向符號者，40公尺", "A級：顯示避難方向符號者，30公尺", "B級：未顯示避難方向符號者，30公尺", "B級：顯示避難方向符號者，30公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01119', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備檢修及申報作業基準規定，下列有關火警自動警報設備綜合檢查敘述，何者錯誤？', '["同時動作：操作火災試驗開關及回路選擇開關，不要復舊使任意五回路，進行火災動作表示試驗", "距音響裝置設置位置中心1公尺處，確認地區音響裝置音壓", "音壓使用簡易或普通噪音計測定", "地區音響裝置音壓，音壓應在85分貝以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01120', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法規定，可燃性高壓氣體儲存場所，下列敘述何 者錯誤？', '["保持攝氏40度以下之溫度；容器並應防止日光之直射", "通路面積至少應占儲存場所面積之百分之二十以上", "周圍2公尺範圍內，應嚴禁煙火，且不得存放任何可燃性物質", "採用不燃材料構造之地面一層建築物，屋簷應距離地面1.5公尺以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01121', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「滅火器認可基準」對於噴射性能試驗規定之敘述，何者錯誤？', '["操作噴射時，能使滅火劑迅速有效噴射", "噴射時間，於溫度25℃時，有10秒鐘以上", "具有有效滅火之噴射距離", "能噴射所充填滅火劑容量或重量90% 以上之量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01122', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依六類公共危險物品緊急應變搶救代碼標示內容及位置注意要點之規定：六類物品容器外部標示之緊急應 變搶救代碼由一個數字及一至二個英文字母組成。數字部分：代表六類物品發生火災或洩漏時，於緊急處 理使用滅火劑之優先選擇，其中數字「3」表示應優先選擇下列何種滅火劑？', '["泡沫", "水柱", "水霧", "乾粉"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
